using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
}

/// <summary>
/// Extractive summarization service that ranks sentences by word frequency
/// and returns the top-scoring sentences in their original order.
/// </summary>
public class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "is", "are", "was", "were", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "need", "dare", "ought",
        "used", "to", "of", "in", "for", "on", "with", "at", "by", "from",
        "as", "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further", "then",
        "once", "and", "but", "or", "nor", "not", "so", "yet", "both", "either",
        "neither", "each", "every", "all", "any", "few", "more", "most", "other",
        "some", "such", "no", "only", "own", "same", "than", "too", "very",
        "just", "because", "if", "when", "where", "how", "what", "which", "who",
        "whom", "this", "that", "these", "those", "i", "me", "my", "myself",
        "we", "our", "ours", "ourselves", "you", "your", "yours", "yourself",
        "he", "him", "his", "himself", "she", "her", "hers", "herself",
        "it", "its", "itself", "they", "them", "their", "theirs", "themselves"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences but preserve original order
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i)
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end of string
        var raw = System.Text.RegularExpressions.Regex
            .Split(text, @"(?<=[.!?])\s+");

        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        return freq;
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => wordFrequencies[w]);

            // Normalize by sentence length to avoid bias toward long sentences
            scores.Add(score / words.Count);
        }

        return scores;
    }

    private static List<string> Tokenize(string text)
    {
        return System.Text.RegularExpressions.Regex
            .Matches(text.ToLowerInvariant(), @"\b[a-z]+\b")
            .Select(m => m.Value)
            .ToList();
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

